import { ArtifactListCard } from '@/components/ArtifactList/ArtifactListCard';
import { ErrorState } from '@/components/Loading/ErrorState';
import { LoadingState } from '@/components/Loading/LoadingState';
import { store } from '@/store';
import { Auth } from '@/store/_auth';
import { Config } from '@/store/_config';
import { Editor } from '@/store/_editor';
import {
  type Artifact,
  type Chapter,
  type Job,
  type Novel,
  type User,
  type Volume,
} from '@/types';
import { JobType } from '@/types/enums';
import { stringifyError } from '@/utils/errors';
import { DeploymentUnitOutlined, LeftOutlined } from '@ant-design/icons';
import { Divider, Grid, Space, Typography } from 'antd';
import axios from 'axios';
import { LRUCache } from 'lru-cache';
import { useEffect, useMemo, useState } from 'react';
import { useSelector } from 'react-redux';
import { Link, useParams } from 'react-router-dom';
import { JobList } from '../JobList';
import { ChapterDetailsCard } from '../NovelDetails/ChapterDetailsCard';
import { NovelDetailsCard } from '../NovelDetails/NovelDetailsCard';
import { VolumeDetailsCard } from '../NovelDetails/VolumeDetailsCard';
import { JobDetailsCard } from './JobDetailsCard';
import { UserDetailsCard } from './UserDetailsCard';

const TRANSLATION_JOBS = new Set([
  JobType.NOVEL_TRANSLATION,
  JobType.NOVEL_TRANSLATION_BATCH,
  JobType.FULL_NOVEL_TRANSLATION,
  JobType.FULL_NOVEL_TRANSLATION_BATCH,
  JobType.VOLUME_TRANSLATION,
  JobType.VOLUME_TRANSLATION_BATCH,
  JobType.CHAPTER_TRANSLATION,
  JobType.CHAPTER_TRANSLATION_BATCH,
]);

const _cache = new LRUCache<string, any>({
  max: 1000,
  ttl: 30000,
});

async function handleFetch<T>(
  name: string,
  id: string | null | undefined,
  setValue: (value: T | undefined) => any,
  refreshCache?: boolean,
  params?: Record<string, string>
) {
  if (!id) {
    setValue(undefined);
    return;
  }
  const url = `/api/${name}/${id}`;
  const key = `${url}${params}`;
  if (refreshCache || !_cache.has(key)) {
    try {
      const res = await axios.get<T>(url, { params });
      _cache.set(key, res.data);
    } catch {
      _cache.set(key, undefined);
    }
  }
  setValue(_cache.get(key));
}

export const JobDetailsPage: React.FC<any> = () => {
  const { lg } = Grid.useBreakpoint();
  const { id } = useParams<{ id: string }>();
  const isLocalUser = useSelector(Auth.select.isLocal);
  const jobDetailsPollIntervalMs = useSelector(
    Config.select.jobDetailsPollIntervalMs
  );

  const [refreshId, setRefreshId] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string>();

  const [job, setJob] = useState<Job>();
  const [user, setUser] = useState<User | undefined>();
  const [novel, setNovel] = useState<Novel | undefined>();
  const [volume, setVolume] = useState<Volume | undefined>();
  const [chapter, setChapter] = useState<Chapter | undefined>();
  const [artifact, setArtifact] = useState<Artifact | undefined>();

  const language = useMemo(
    () =>
      TRANSLATION_JOBS.has(job?.type ?? -1) ? job?.extra.language : undefined,
    [job]
  );

  useEffect(() => {
    const fetchJob = async (id: string) => {
      setError(undefined);
      try {
        const { data: job } = await axios.get<Job>(`/api/job/${id}`);
        setJob(job);
      } catch (err: any) {
        setError(stringifyError(err));
      } finally {
        setLoading(false);
      }
    };
    if (id) {
      fetchJob(id);
    }
  }, [id, refreshId]);

  useEffect(() => {
    if (isLocalUser) return;
    handleFetch('user', job?.user_id, setUser);
  }, [job?.user_id, isLocalUser]);

  useEffect(() => {
    const canRefresh = job?.done !== job?.total;
    const params = language ? { language } : undefined;
    handleFetch('novel', job?.extra.novel_id, setNovel, canRefresh, params);
  }, [job?.extra.novel_id, language, job?.type, job?.done, job?.total]);

  useEffect(() => {
    handleFetch('volume', job?.extra.volume_id, setVolume, job?.is_done);
  }, [job?.extra.volume_id, job?.is_done]);

  useEffect(() => {
    handleFetch('chapter', job?.extra.chapter_id, setChapter, job?.is_done);
  }, [job?.extra.chapter_id, job?.is_done]);

  useEffect(() => {
    handleFetch('artifact', job?.extra.artifact_id, setArtifact, job?.is_done);
  }, [job?.extra.artifact_id, job?.is_done]);

  useEffect(() => {
    if (!job?.is_done) {
      const iid = setInterval(() => {
        setRefreshId((v) => v + 1);
      }, jobDetailsPollIntervalMs);
      return () => {
        clearInterval(iid);
      };
    }
  }, [job?.is_done, jobDetailsPollIntervalMs]);

  useEffect(() => {
    if (!novel) return;
    store.dispatch(Editor.action.addNovelUrl(novel.url));
  }, [novel]);

  if (loading) {
    return <LoadingState />;
  }

  if (!job) {
    return (
      <ErrorState
        error={error}
        title="Failed to load request"
        onRetry={() => {
          setLoading(true);
          setRefreshId((v) => v + 1);
        }}
      />
    );
  }

  return (
    <Space vertical size={lg ? 'middle' : 'small'}>
      {job.parent_job_id ? (
        <Link to={`/job/${job.parent_job_id}`}>
          <LeftOutlined /> Parent Request
        </Link>
      ) : (
        <Link to="/">
          <LeftOutlined /> All Requests
        </Link>
      )}

      <JobDetailsCard job={job} />
      {user && <UserDetailsCard user={user} title="Initiated By" />}
      {novel && (
        <NovelDetailsCard
          novel={novel}
          withPageLink
          hideActions
          pageLink={language && `/novel/${novel.id}/${job.extra.language}`}
        />
      )}
      {volume && <VolumeDetailsCard volume={volume} hideChapters />}
      {chapter && <ChapterDetailsCard chapter={chapter} />}
      {artifact && <ArtifactListCard artifacts={[artifact]} />}

      <JobList
        key={job.id + job.is_done}
        parentJobId={job.id}
        autoRefresh={!job.is_done}
        hideIfEmpty
        title={
          <>
            <Divider style={{ margin: 0 }} />
            <Typography.Title level={3}>
              <DeploymentUnitOutlined /> Linked Requests
            </Typography.Title>
          </>
        }
      />
    </Space>
  );
};
